import styled from 'styled-components';

const FooterBox = styled.div`

`;
const ContactChannelIcon = styled.img`
    display:inline-block;
    margin: 5px;
    width:32px;
`;

export const Footer = () =>
{
  return (<FooterBox>
        <ContactChannelIcon src="twitter.svg"></ContactChannelIcon>
    </FooterBox>);
}
